INSERT INTO public.photos VALUES (24127, 'Plaza de la Constituciâ”śâ”‚n 1916', 'Fotograma de un reportaje dedicado a la multitudinaria comitiva que acompaâ”śâ–’â”śâ”‚ a los exploradores zaragozanos (asociaciâ”śâ”‚n constituida unos aâ”śâ–’os antes e inspirada en los Boy Scouts de Robert Baden-Powell) que en nâ”śâ•‘mero de doce, mâ”śĂ­s un jefe instructor fueron andando hasta Madrid para entregar al periodista local Mariano de Cavia ("el Cervantes de la Espaâ”śâ–’a de hoy") un mensaje de felicitaciâ”śâ”‚n acompaâ”śâ–’ado de doce mil firmas con motivo de haberle concedido el Gobierno la gran Cruz de Alfonso XII. Mientras que el viaje de ida fue cubierto con jornadas de 30 kilâ”śâ”‚metros diarios "en el coche de San Servando", los exploradores realizaron el viaje de vuelta en el râ”śĂ­pido de la tarde del 16 de marzo de ese aâ”śâ–’o, llegando hasta la estaciâ”śâ”‚n de Campo Sepulcro donde fueron recibidos por una multitud que luego les acompaâ”śâ–’â”śâ”‚ por el centro de la ciudad y en comitiva hasta el templo del Pilar. La imagen se centra en el paso por la plaza de la Constituciâ”śâ”‚n del automâ”śâ”‚vil A. Darracq con matrâ”śÂˇcula nâ”śâ•‘mero 21 de Zaragoza, integrante de la comitiva y flanqueado por numeroso pâ”śâ•‘blico.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65198400, -0.88127700, '0101000020E610000099F1B6D26B33ECBFF4C1323674D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54709251680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54709251680.webp', 'https://www.flickr.com/photos/zaragozaantigua/54709251680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24161, 'Coso Alto 1925', 'Imagen del Salâ”śâ”‚n de fiestas del Centro Mercantil, habilitado como escenario expositivo del I Salâ”śâ”‚n Internacional de Fotografâ”śÂˇa organizado por la Sociedad Fotogrâ”śĂ­fica de Zaragoza. En el grupo central, y de espaldas, el fotâ”śâ”‚grafo Juan Mora Insa. Fuente visual: www.rsfz.es/', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65274200, -0.88126800, '0101000020E6100000CD5CE0F25833ECBFE25CC30C8DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33414861810.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33414861810.webp', 'https://www.flickr.com/photos/zaragozaantigua/33414861810/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24221, 'Plaza Espaâ”śâ–’a 1958', 'Octubre de 1958. Plaza de Espaâ”śâ–’a de Zaragoza, vista desde su confluencia con el paseo de la Independencia. Se distinguen a la izquierda las barandillas de los urinarios pâ”śâ•‘blicos. Las luces decorativas colocadas con motivo de las fiestas del Pilar compiten con los neones publicitarios. Fuente: Colecciâ”śâ”‚n Josâ”śÂ® Vicente Moreno.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65168700, -0.88123200, '0101000020E61000009A0986730D33ECBF3B1DC87A6AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15788691876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15788691876.webp', 'https://www.flickr.com/photos/zaragozaantigua/15788691876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24222, 'Congreso catâ”śâ”‚lico 1890', 'Segundo Congreso Catâ”śâ”‚lico Nacional Espaâ”śâ–’ol. Zaragoza, octubre de 1890. Entre los actos de este rancio evento, la ilustraciâ”śâ”‚n refleja la actuaciâ”śâ”‚n de una banda de mâ”śâ•‘sica militar en la plaza de la Constituciâ”śâ”‚n, aparte de lo que sea que estâ”śÂ®n haciendo en el estrado de la derecha, ante el edificio de la Diputaciâ”śâ”‚n Provincial.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65202200, -0.88126700, '0101000020E6100000B66801DA5633ECBFE222F77475D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15889916902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15889916902.webp', 'https://www.flickr.com/photos/zaragozaantigua/15889916902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24482, 'Bazar X 1970', 'Foto: Josâ”śÂ® Laporta. Situado en el nâ”śâ•‘mero 25 del Coso Alto, el Bazar X cerrâ”śâ”‚ en enero de 1974. En su ubicaciâ”śâ”‚n se levanta hoy el comercio FNAC. Fuente: www.rafaelcastillejo.com', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65299200, -0.88161000, '0101000020E61000002E73BA2C2636ECBF5A46EA3D95D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23219434114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23219434114.webp', 'https://www.flickr.com/photos/zaragozaantigua/23219434114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24518, 'Galerâ”śÂˇas Preciados 1971', 'El sâ”śĂ­bado 27 de marzo de 1971 a las 19.30 y en la planta sexta se inauguraron los grandes almacenes Galerâ”śÂˇas Preciados, en el paseo de la Independencia 13, segâ”śâ•‘n proyecto de 1969 de Francisco Bassâ”śâ”‚ Birulâ”śÂ®s y Javier Martâ”śÂˇnez Feduchi. El acto estuvo presidido por el presidente de la Audiencia Territorial, Josâ”śÂ® Hijas Palacios, acompaâ”śâ–’ado del presidente de la Diputaciâ”śâ”‚n Provincial, Pedro Baringo Rosinach, el fiscal de la Audiencia, Luis Martâ”śÂˇn Ballesteros, el rector de la Universidad, Justiniano Casas Pelâ”śĂ­ez, el alcalde, Mariano Horno Liria, el delegado de Informaciâ”śâ”‚n y Turismo, Enrique Gonzâ”śĂ­lez Albaladejo, el jefe superior de Policâ”śÂˇa, Joaquâ”śÂˇn Dâ”śÂˇaz Moreno, el delegado provincial de Sindicatos, Rafael Ruiz Ortega, el delegado provincial de Trabajo, Camilo Sueiro Rodrâ”śÂˇguez, y Josâ”śÂ® Manuel Fernâ”śĂ­ndez, hijo del dueâ”śâ–’o y fundador de Galerâ”śÂˇas Preciados, Josâ”śÂ® "Pepâ”śÂˇn" Fernâ”śĂ­ndez Rodrâ”śÂˇguez. Asistieron tambiâ”śÂ®n los directores de las emisoras de radio, de la prensa y de las entidades bancarias locales. David Aznar, de la parroquia de San Miguel, bendijo las instalaciones invocando a la Virgen del Pilar, momento que recoge la imagen. Los asistentes rezaron un Ave Marâ”śÂˇa por la prosperidad de ese comercio, cuya casa madre fue fundada en 1943 en Madrid. En 1979 el control pasa al Banco Urquijo, con el que se habâ”śÂˇa endeudado, y en 1981 lo compra Rumasa, empresa del estafador del Opus Dei Josâ”śÂ® Marâ”śÂˇa Ruiz-Mateos expropiada en 1983. El multimillonario venezolano Gustavo Cisneros, câ”śâ”‚mplice del presidente del gobierno Felipe Gonzâ”śĂ­lez, lo comprâ”śâ”‚ al Estado por 750 millones de pesetas en 1984, vendiâ”śÂ®ndolo por 30.000 millones en 1987. Tras otros cambios de manos, en 1995 fue absorbido por su rival, El Corte Inglâ”śÂ®s. Fuente: "Boletâ”śÂˇn Galerâ”śÂˇas Preciados", abril de 1971. Colecciâ”śâ”‚n particular de Fernando Defboy.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65099400, -0.88162000, '0101000020E610000011FC6F253B36ECBF34F279C553D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36398335162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36398335162.webp', 'https://www.flickr.com/photos/zaragozaantigua/36398335162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24542, 'P.â”¬â•‘ de la Independencia 1962', 'Inâ”śÂ®dita imagen capturada en el interior de la tienda de "venta de aparatos" electrodomâ”śÂ®sticos de la empresa Gas de Zaragoza SA sita en el nâ”śâ•‘mero 11 del paseo de la Independencia y centrada en una seâ”śâ–’orita dependienta atendiendo el telâ”śÂ®fono (tal vez el aparato menos "moderno" de todos los que aparecen en la imagen) tras su mesa de escritorio. Completan el posado publicitario algunos de los aparatos electrodomâ”śÂ®sticos que utilizaban el gas butano como combustible y que podâ”śÂˇan adquirirse en este espacio comercial: cocinas de diversos tamaâ”śâ–’os, termo de agua caliente, etc., e incluso artilugios complementarios como el "Transportâ”śÂˇn Uclâ”śÂ®s" que facilitaba el transporte y manejo de la bombona de butano en el domicilio particular de las usuarias. No muy lejos, en el nâ”śâ•‘mero 10 de la calle de San Miguel, el "Palacio de la Luz" o sede social de esta empresa contaba con otra tienda de estas mismas caracterâ”śÂˇsticas. Primeros signos de una sociedad de consumo a la espaâ”śâ–’ola.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65109400, -0.88163100, '0101000020E61000000C7904375236ECBF984F560C57D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53158694570.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53158694570.webp', 'https://www.flickr.com/photos/zaragozaantigua/53158694570/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24546, 'Coso alto c.1948', 'Portada del nâ”¬â•‘ 27 del tramo alto del Coso donde estaba ubicado el establecimiento comercial "Bazar X", con el aspecto tras la reforma proyectada por los arquitectos Teodoro Râ”śÂˇos Balaguer y Teodoro Râ”śÂˇos Usâ”śâ”‚n a comienzos de los aâ”śâ–’os 40.', 1948, 1948, 1948, 'Anos 40', 'CENTRO', 41.65287500, -0.88159100, '0101000020E61000007E552E54FE35ECBF21B0726891D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54395670738.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54395670738.webp', 'https://www.flickr.com/photos/zaragozaantigua/54395670738/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24851, 'Calle de la Independencia c.1899', 'Imagen de la calle de la Independencia en su tramo de los pares mâ”śĂ­s inmediato a la plaza de la Constituciâ”śâ”‚n, entre los porches y el arbolado andâ”śÂ®n central. La esquina de primer plano mutarâ”śĂ­ unas cuantas veces en el siglo venidero. Al fondo, la fachada del Coso a esta plaza. El estacionamiento de vehâ”śÂˇculos, libre. Se trata de otra de las postales de la serie de "Laurent" realizada aâ”śâ–’os despuâ”śÂ®s de la muerte del gran fotâ”śâ”‚grafo Jean Laurent. Fuente visual: www.delcampe.es/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65173400, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF7BD80B056CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24556723629.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24556723629.webp', 'https://www.flickr.com/photos/zaragozaantigua/24556723629/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24852, 'Pl. de Espaâ”śâ–’a 1937', 'Imagen capturada durante las fiestas mayores de la ciudad en octubre y centrada en el ingreso a la plaza de Espaâ”śâ–’a (hasta julio del aâ”śâ–’o anterior, de la Constituciâ”śâ”‚n) de una carroza de militares y bellas seâ”śâ–’oritas disfrazadas para la ocasiâ”śâ”‚n de forma tradicionalista. Entre los comerciales audiovisuales destaca el del documental propagandâ”śÂˇstico "El viaje de Mussolini a Alemania" realizado durante el pasado mes de septiembre, donde se explicitaba la comuniâ”śâ”‚n de intereses del Eje Roma-Berlâ”śÂˇn y que se proyectaba por la axial admiraciâ”śâ”‚n que despertaba en la Espaâ”śâ–’a alzada en armas contra la democracia republicana. En la esquina de los porches del paseo de la Independencia se conservaba la placa con la antigua denominaciâ”śâ”‚n de Calle de la Independencia. Al fondo, a la derecha, el Banco de Espaâ”śâ–’a y el cafâ”śÂ® Salduba. Fuente visual: Michele Francone, en Francone: La mirada de Mussolini en la guerra de Espaâ”śâ–’a (catâ”śĂ­logo exposiciâ”śâ”‚n), DGA, 2009.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65170500, -0.88139400, '0101000020E6100000FE7F9C306134ECBFE1D1C6116BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28054895929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28054895929.webp', 'https://www.flickr.com/photos/zaragozaantigua/28054895929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24854, 'Pl. de Espaâ”śâ–’a 1976', 'Imagen de la huelga total de trabajadores de los transportes urbanos durante las fiestas del Pilar. La escena tiene lugar en la parada sita en la plaza de Espaâ”śâ–’a de la lâ”śÂˇnea 30. Las Fuentes-Casablanca, en direcciâ”śâ”‚n al barrio de Casablanca. El autobâ”śâ•‘s estâ”śĂ­ conducido por personal del Parque Mâ”śâ”‚vil de los ministerios civiles, escoltados de forma preventiva por dos miembros de la Policâ”śÂˇa Armada. Al fondo, el edificio del Banco de Espaâ”śâ–’a.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65223900, -0.88162100, '0101000020E610000028F04E3E3D36ECBF7F164B917CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30861623802.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30861623802.webp', 'https://www.flickr.com/photos/zaragozaantigua/30861623802/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25085, 'P.â”¬â•‘ de la Independencia 1965', 'Imagen capturada con ocasiâ”śâ”‚n de las locales fiestas del mes de octubre, centrada en la artâ”śÂˇstica pareja estelar del Circo Atlas: los "Hermanos Tonetti", Josâ”śÂ® y Manuel Villa del Râ”śÂˇo. Al fondo, el bloque del nâ”¬â•‘ 5 y 7 del paseo, renombrado por albergar la cafeterâ”śÂˇa Las Vegas, inaugurada diez aâ”śâ–’os antes. A la derecha, el emboque a la calle de San Miguel. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65141600, -0.88143700, '0101000020E6100000D07F0F5EBB34ECBFAA0B789961D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30813064823.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30813064823.webp', 'https://www.flickr.com/photos/zaragozaantigua/30813064823/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25095, 'Sofâ”śÂˇa y los niâ”śâ–’os 1970', 'Foto: Luis Mompel. Plaza de Espaâ”śâ–’a. La princesa Sofâ”śÂˇa de Grecia participa en la ofrenda de flores a la Virgen del Pilar junto a sus tres hijos, ataviados al uso. Una corte de seâ”śâ–’oras con grâ”śĂ­ciles peinados les acompaâ”śâ–’a. Al fondo, el paseo de la Independencia. Fuente: Heraldo de Aragâ”śâ”‚n.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65193700, -0.88129200, '0101000020E6100000EE3EC7478B33ECBFB306EFAB72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33452957916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33452957916.webp', 'https://www.flickr.com/photos/zaragozaantigua/33452957916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25267, 'Pl. de la Constituciâ”śâ”‚n 1930', 'Diciembre y a la solana en la plaza de la Constituciâ”śâ”‚n, en una imagen tomada desde cierta altura en el edificio de La Catalana. Abajo a la izquierda, junto a los evacuatorios del principio del paseo de la Independencia, terminal de la lâ”śÂˇnea 5. Torrero del tranvâ”śÂˇa, donde una unidad de la serie 40 estâ”śĂ­ a punto de iniciar su recorrido hacia el sur. La inhabitual presencia de guardiaciviles a pie en el paseo y junto a la parada de tranvâ”śÂˇa, a caballo ante la Diputaciâ”śâ”‚n Provincial, asâ”śÂˇ como de tropas regulares desplegadas junto al Monumento a los Mâ”śĂ­rtires de la Religiâ”śâ”‚n y de la Patria, son ecos de la republicana Sublevaciâ”śâ”‚n de Jaca de unos dâ”śÂˇas antes, y de las medidas para asegurar el orden vigente en los puntos estratâ”śÂ®gicos de la ciudad, con la plaza de la Constituciâ”śâ”‚n como uno de los mâ”śĂ­s importantes. Al fondo y a la sombra, la fachada de la Diputaciâ”śâ”‚n Provincial proyectada por Pedro Martâ”śÂˇnez Sangrâ”śâ”‚s.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65234400, -0.88149100, '0101000020E61000009CFC169D2C35ECBFF4DE180280D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14682013000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14682013000.webp', 'https://www.flickr.com/photos/zaragozaantigua/14682013000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25270, 'P.â”¬â•‘ de la Independencia 1966', 'AYUNTAMIENTO DE ZARAGOZA/Gerardo Sancho Ramo. 29/01/1966. Inicialmente denominada "Rue Impâ”śÂ®rial", despuâ”śÂ®s "Salâ”śâ”‚n de Santa Engracia", y desde 1860 "Paseo de la Independencia", esta vâ”śÂˇa urbana se realizâ”śâ”‚ segâ”śâ•‘n proyecto de Joaquâ”śÂˇn Asensio, que en 1811 habâ”śÂˇa sido nombrado arquitecto municipal por el gobernador general de Aragâ”śâ”‚n, mariscal Luis Gabriel de Suchet. Algo mâ”śĂ­s de un siglo despuâ”śÂ®s de recibir su vigente denominaciâ”śâ”‚n, esta imagen captura el estado de las cosas en la acera de los impares, entre el nâ”śâ•‘mero 11 y el 19. A la izquierda, apenas visible, hacâ”śÂˇa esquina con San Miguel un bloque de 8 plantas de oficinas, construido en 1955. Despuâ”śÂ®s, todo el frontal de los nâ”śâ•‘meros 11, 13, 15 y 17, que se correspondâ”śÂˇan con la tâ”śÂˇpica tipologâ”śÂˇa de edificios eclecticistade finales del XIX muy zaragozana, en 3-4 alturas, que ademâ”śĂ­s no presentaban los arcos o porches que luego caracterizarâ”śÂˇan al Paseo. A continuaciâ”śâ”‚n, el edificio de La Equitativa, de 1950, con el colosal cine del mismo nombre en su planta calle. Los edificios de 3 y 4 plantas serâ”śÂˇan luego piqueteados, y en el solar resultante se construirâ”śÂˇa en 1971 el edificio de Galerâ”śÂˇas Preciados, una de las mecas del consumo de masas de aquellos aâ”śâ–’os. En 1995 serâ”śÂˇa, a su vez, consumido por una empresa aâ”śâ•‘n mâ”śĂ­s voraz, que perdura en nuestros dâ”śÂˇas. Transita por el Paseo la unidad M107+R107 de la Lâ”śÂˇnea 5 del tranvâ”śÂˇa Venecia-Delicias. Detrâ”śĂ­s de â”śÂ®l, protoautobâ”śâ•‘s urbano listo para torpedearlo. Conseguirâ”śĂ­ hundirlo unos aâ”śâ–’os despuâ”śÂ®s. Momentâ”śĂ­neamente.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65131800, -0.88177600, '0101000020E6100000EDB94C4D8237ECBFE8A562635ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14852574375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14852574375.webp', 'https://www.flickr.com/photos/zaragozaantigua/14852574375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25286, 'Estado de Guerra Febrero 1936', 'Miguel Marâ”śÂˇn Chivite. 17.02.1936. En la imagen, un piquete de infanterâ”śÂˇa lee en la plaza de la Constituciâ”śâ”‚n (tras haberlo hecho antes enante el edificio de Capitanâ”śÂˇa General) la orden del general Cabanellas que declaraba el "Estado de Guerra" en Zaragoza tras las elecciones ganadas por el Frente Popular. El gobierno en funciones desautorizarâ”śĂ­ poco despuâ”śÂ®s la medida. Fuente visual: somoszaragoza.files.wordpress.com/2011/07/zaragoza-20-07-...', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65200800, -0.88146300, '0101000020E61000001F4AB4E4F134ECBF7D5D86FF74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15575939110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15575939110.webp', 'https://www.flickr.com/photos/zaragozaantigua/15575939110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25289, 'Plaza Constituciâ”śâ”‚n c.1902', 'Plaza de la Constituciâ”śâ”‚n, hoy de Espaâ”śâ–’a, poblada de vehâ”śÂˇculos rodantes, hacia 1902, fecha en la que se electrificâ”śâ”‚ la primera lâ”śÂˇnea tranviaria. Al fondo, la entrada al Tubo por la calle Mâ”śĂ­rtires. Fuente: www.facebook.com/photo.php?fbid=872321992808797&set=o...', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65223200, -0.88128200, '0101000020E61000000BB6114F7633ECBFCCB392567CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15703578160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15703578160.webp', 'https://www.flickr.com/photos/zaragozaantigua/15703578160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25297, 'Pl. de Espaâ”śâ–’a 1987', 'Locomotora Baldwin, llamada Aragâ”śâ”‚n y fabricada en 1920 en Filadelfia (USA). Procedente del depâ”śâ”‚sito de Andorra (Teruel), fue colocada sobre un pedestal en la plaza de Espaâ”śâ–’a durante la exposiciâ”śâ”‚n El tren en Aragâ”śâ”‚n, celebrada en el palacio de Sâ”śĂ­stago entre el 4 de octubre y el 1 de noviembre de 1987, donde se mostraba ademâ”śĂ­s un documental con el proceso de su restauraciâ”śâ”‚n entre 1985 y 1987. Actualmente se encuentra en Casetas, en las instalaciones de la Asociaciâ”śâ”‚n Zaragozana de Amigos del Ferrocarril y el Tranvâ”śÂˇa, Azaft, mientras sigue Esperando a Godot, que en este caso es el utâ”śâ”‚pico Museo del Ferrocarril en Aragâ”śâ”‚n. En la imagen, la locomotora rodeada de nostâ”śĂ­lgicos del tren convencional, precedida de una larga cola de espera en las paradas de autobâ”śâ•‘s urbano de la plaza durante las fiestas de octubre. En primer tâ”śÂ®rmino y a la derecha, seâ”śâ–’ales indicativas para el trâ”śĂ­fico de la â”śÂ®poca.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65220700, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF739CDB847BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19255446562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19255446562.webp', 'https://www.flickr.com/photos/zaragozaantigua/19255446562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25303, 'Urinarios c.1956', 'Escaleras de entrada a los urinarios en la confluencia del paseo de la Independencia con la plaza de Espaâ”śâ–’a, y filas en las paradas de tranvâ”śÂˇas. Fuente: rafaelcastillejo.com', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65187800, -0.88131000, '0101000020E610000088687407B133ECBFAF7D01BD70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20519407598.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20519407598.webp', 'https://www.flickr.com/photos/zaragozaantigua/20519407598/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25306, 'Evacuatorios 1956', 'Foto: Josâ”śÂ® Antonio Duce. Escaleras de acceso a los baâ”śâ–’os pâ”śâ•‘blicos de la confluencia del paseo de la Independencia con la plaza de Espaâ”śâ–’a de Zaragoza, en 1956. Fuente: rafaelcastillejo.com', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65187800, -0.88131000, '0101000020E610000088687407B133ECBFAF7D01BD70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20703585052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20703585052.webp', 'https://www.flickr.com/photos/zaragozaantigua/20703585052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25308, 'Quiosco de la Mâ”śâ•‘sica 1914', '"Jura de bandera en Zaragoza". Al fondo, tras la plaza de la Constituciâ”śâ”‚n, una torre del Pilar. Fuente: Fotografâ”śÂˇa de Aurelio Grasa publicada en Heraldo de Aragâ”śâ”‚n el dâ”śÂˇa 16 de febrero de 1914. En ABC el 17 de febrero de 1914 y en el Blanco y Negro el 22 de febrero de 1914. El periâ”śâ”‚dico ABC conserva una copia de esa fotografâ”śÂˇa de Aurelio Grasa que el mismo enviâ”śâ”‚ para su publicaciâ”śâ”‚n. El Archivo Barboza Grasa conserva mâ”śĂ­s imâ”śĂ­genes del acontecimiento. www.aureliograsa.es', 1914, 1914, 1914, 'Anos 10', 'CENTRO', 41.65124500, -0.88181400, '0101000020E61000004DF564FED137ECBF7E5704FF5BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21413701855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21413701855.webp', 'https://www.flickr.com/photos/zaragozaantigua/21413701855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25326, 'Elecciones 1936', 'En febrero de 1936 se celebraron en Espaâ”śâ–’a las terceras y â”śâ•‘ltimas elecciones generales de la Segunda Repâ”śâ•‘blica. Las siguientes tuvieron que esperar 41 aâ”śâ–’os. En la imagen, entre el paseo de la Independencia a la izquierda y la plaza de la Constituciâ”śâ”‚n a la derecha, pilar de los porches como soporte de carteles electorales y comerciales. Fuente: "Trabajo, sociedad, cultura. Una mirada al siglo XX en Aragâ”śâ”‚n", UGT, 2000.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65197400, -0.88157800, '0101000020E610000056F0DB10E335ECBFD1EB4FE273D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24061552696.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24061552696.webp', 'https://www.flickr.com/photos/zaragozaantigua/24061552696/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25334, 'Plaza de Espaâ”śâ–’a 1955', 'Excepcional e insâ”śâ”‚lita imagen desde la plaza de Espaâ”śâ–’a, centrada en un tramo de la antigua fachada que iluminaba la vista entre los nâ”śâ•‘meros impares 27 y 33 del Coso Alto, en torno al edificio del Casino Mercantil, construido a principios del siglo XX ("de toda la vida") sobre la antigua casa de Juan Coloma. Este pedazo de lienzo urbano serâ”śÂˇa notablemente modificado mâ”śĂ­s tarde, pero, de momento, todavâ”śÂˇa era posible ver, en el nâ”¬â•‘ 27, la antigua casa de Martâ”śÂˇn Zapater (â”śÂˇntimo de Goya); en el nâ”¬â•‘ 29, el modernista Centro Mercantil, Industrial y Agrâ”śÂˇcola, aâ”śâ•‘n con su "minarete" de funciones columbâ”śâ”‚filas; en el nâ”¬â•‘ 31, la antigua casa de los marqueses de Nibbiano, remodelada con destacable decoraciâ”śâ”‚n historicista, que perdurarâ”śĂ­ hasta que sea radicalmente transformada por la entidad bancaria que se anuncia en sus bajos. Notable es la presencia, en este edificio, del estudio fotogrâ”śĂ­fico de Carlos Skogler. Inmediato, para terminar, el veterano nâ”¬â•‘ 33, otra antigua casa de los Nibbiano que fue pasando de manos en manos hasta terminar en las de otra entidad bancaria, y desde 1936, como vistosa y câ”śÂ®ntrica delegaciâ”śâ”‚n provincial del partido polâ”śÂˇtico Falange Espaâ”śâ–’ola de las JONS, como parte del autoproclamado "Movimiento Nacional" franquista. En sus caracterâ”śÂˇsticos colores, transita hacia el Coso la unidad 33 de la tranviaria lâ”śÂˇnea 7, o del Ayuntamiento, en su trayecto desde la plaza de Espaâ”śâ–’a, hasta el Portillo. Esta unidad tuvo una (hoy) inimaginable y longeva vida â”śâ•‘til: desde 1918, y hasta su forzado desguace en 1971. Esta joya visual fue realizada por el fotâ”śâ”‚grafo francâ”śÂ®s Jean Paul Margnac en el verano de 1955, durante su paso por la penâ”śÂˇnsula Ibâ”śÂ®rica, desde Parâ”śÂˇs, y con destino hacia tierras mâ”śĂ­s meridionales. Fuente visual: www.flickr.com/photos/jean-paul-margnac/26658972851/in/al...', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65255900, -0.88123500, '0101000020E6100000DEE522BE1333ECBFF0DAA50D87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26694889163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26694889163.webp', 'https://www.flickr.com/photos/zaragozaantigua/26694889163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25337, 'Pl. de Espaâ”śâ–’a 1965', 'Tranvâ”śÂˇa de la lâ”śÂˇnea 15 "Casablanca", en la plaza de Espaâ”śâ–’a, enfilado hacia ese perifâ”śÂ®rico destino. Al fondo, la fachada del Coso y sus anuncios luminosos (de noche). Fuente: "Trenes y tranvâ”śÂˇas en el este de Espaâ”śâ–’a", Jeremy Wiseman, Ediciones Treca SL, Gijâ”śâ”‚n 2009, a travâ”śÂ®s de www.facebook.com/photo.php?fbid=648401765324491&set=g...', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65199800, -0.88132100, '0101000020E610000082E50819C833ECBF5987A3AB74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27785196316.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27785196316.webp', 'https://www.flickr.com/photos/zaragozaantigua/27785196316/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25338, 'Plaza de la Constituciâ”śâ”‚n 1899', 'Imagen de la fachada oeste de la plaza de la Constituciâ”śâ”‚n, esquinera con el Coso alto (a la derecha), donde destaca la imponente y albina presencia del palacio de la Diputaciâ”śâ”‚n Provincial diseâ”śâ–’ado por Martâ”śÂˇnez Sangrâ”śâ”‚s. A su lado, el edificio de viviendas del nâ”¬â•‘ 1 de la plaza, que apenas un par de aâ”śâ–’os antes habâ”śÂˇa sido remozado por Fernando de Yarza Fernâ”śĂ­ndez Treviâ”śâ–’o, y en cuyos bajos estaba el referente establecimiento "Gambrinus", que comenzâ”śâ”‚ siendo cervecerâ”śÂˇa, y luego se especializâ”śâ”‚ como destacado cafâ”śÂ®. Este edificio serâ”śÂˇa notablemente modificado (y recrecido) al comienzo de los aâ”śâ–’os 20, con proyecto de Teodoro Râ”śÂˇos Balaguer. La Diputaciâ”śâ”‚n mutarâ”śÂˇa radicalmente (tambiâ”śÂ®n en apariencia) en los aâ”śâ–’os 40, con proyecto del mismo arquitecto. Fuente visual: Francisco Gâ”śâ”‚rriz, Archivo Municipal de Zaragoza', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65241000, -0.88146900, '0101000020E6100000A702EE79FE34ECBFACCABE2B82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28056865723.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28056865723.webp', 'https://www.flickr.com/photos/zaragozaantigua/28056865723/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25339, 'P.â”¬â•‘ Independencia 1936', '"Machine gun in a Sarragossa street 1936 Spanish Civil War. Paris, Bibliothâ”śÂżque Nationale". Soldados golpistas posando con su armamento en el inicio del paseo de la Independencia. Fuiente: www.alamy.com/', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65179700, -0.88150400, '0101000020E6100000C36169E04735ECBFC25087156ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28489155745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28489155745.webp', 'https://www.flickr.com/photos/zaragozaantigua/28489155745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25346, 'Pl. de la Constituciâ”śâ”‚n 1936', 'Imagen de las traseras del antiguo edificio de la Diputaciâ”śâ”‚n Provincial, centrada en el alabeado frontâ”śâ”‚n que lo remataba, donde se ubicaba su famoso reloj activo desde 1858, cuando fue instalado tras un interesante viaje desde Parâ”śÂˇs, donde fue compuesto. La esfera de este reloj tenâ”śÂˇa dos metros de diâ”śĂ­metro, y estaba flanqueada por dos representaciones alegâ”śâ”‚ricas de la Noche y el Dâ”śÂˇa. Tras el derribo del edificio, parece ser que el reloj fue transferido a la fachada del Hospital de Gracia. Las alegorâ”śÂˇas, y demâ”śĂ­s motivos decorativos, parece que sucumbieron a la ley de la gravedad. Al fondo, a la derecha, la reconocible câ”śâ•‘pula del Banco Zaragozano, esquinera con la calle de Don Jaime I. Fuente visual: diario "El Noticiero". Archivo Josâ”śÂ® Marâ”śÂˇa Ballestâ”śÂˇn Miguel.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65222100, -0.88155800, '0101000020E61000008FDE701FB935ECBFD8614CFA7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31691763403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31691763403.webp', 'https://www.flickr.com/photos/zaragozaantigua/31691763403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25347, 'Pl. de Espaâ”śâ–’a 1955', 'Imagen capturada desde el andador central del paseo de la Independencia, en direcciâ”śâ”‚n hacia el principio de la calle de Don Jaime I. Destaca el vivo movimiento en torno a los evacuatorios subterrâ”śĂ­neos, a la derecha, bajo un comercial que anuncia la bolera "Strike" de la calle San Miguel nâ”¬â•‘ 16. A la izquierda, los comerciales de neâ”śâ”‚n que caracterizaron con sus luces y colores la nocturnidad de la fachada de los veteranos edificios recayentes a la plaza. Fuente visual: postal de Garcâ”śÂˇa Garrabella, en www.todocoleccion.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65199800, -0.88132100, '0101000020E610000082E50819C833ECBF5987A3AB74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32064248495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32064248495.webp', 'https://www.flickr.com/photos/zaragozaantigua/32064248495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25349, 'Cafeterâ”śÂˇa Gambrinus c.1930', 'Terraza de la cafeterâ”śÂˇa Gambrinus, en la plaza de la Constituciâ”śâ”‚n, junto a la Diputaciâ”śâ”‚n Provincial. Fuente visual de la imagen: Heraldo de Aragâ”śâ”‚n.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65246100, -0.88146100, '0101000020E6100000F261F6B2ED34ECBF2E7590D783D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32707946636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32707946636.webp', 'https://www.flickr.com/photos/zaragozaantigua/32707946636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25365, 'Plaza de la Constituciâ”śâ”‚n 1936', 'Imagen centrada en un pelotâ”śâ”‚n de la sublevada 5â”¬Â¬ Divisiâ”śâ”‚n Orgâ”śĂ­nica, armado con una ametralladora Hotchkiss M1914 y apostado en la plaza de la Constituciâ”śâ”‚n durante la maâ”śâ–’ana del 19 de julio de 1936. Al fondo, fachada del edificio de la Diputaciâ”śâ”‚n Provincial.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65194300, -0.88121200, '0101000020E6100000D3F71A82E332ECBF96ED43DE72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49793035567.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49793035567.webp', 'https://www.flickr.com/photos/zaragozaantigua/49793035567/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25366, 'P.â”¬â•‘ de la Independencia c.1901', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 8 del paseo de la Independencia con una refrescante escena del paseo y de la plaza de la Constituciâ”śâ”‚n, al fondo, en la que destaca la nieve acumulada en el firme y los tejados. Algunos operarios retiran la helada precipitaciâ”śâ”‚n del andâ”śÂ®n central del paseo, y en primer tâ”śÂ®rmino, el paso transversal que conecta por el paseo la calle del Cinco de Marzo y la de San Miguel. Flanqueando el arranque del paseo, las pâ”śÂ®treas estructuras de los urinarios de la â”śÂ®poca, antecedidos por sendos quioscos. En la plaza, Neptuno en paâ”śâ–’os menores e indiferente a la temperatura ambiente. De telâ”śâ”‚n escâ”śÂ®nico, el tramo del Coso comprendido entre la calle de los Mâ”śĂ­rtires y la de Don Jaime I, por encima del cual emerge levemente el remate de la torre de la iglesia parroquial de San Gil Abad, y el mâ”śĂ­s lejano y elevado de la torre de la Seo.', 1901, 1901, 1901, 'Anos 1900', 'CENTRO', 41.65164700, -0.88152400, '0101000020E61000008A73D4D17135ECBFACC43C2B69D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50115369656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50115369656.webp', 'https://www.flickr.com/photos/zaragozaantigua/50115369656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25369, 'Pl. de la Constituciâ”śâ”‚n 1936', 'Un camiâ”śâ”‚n lleno de jâ”śâ”‚venes de la Secciâ”śâ”‚n Femenina de Falange posiblemente celebran el golpe de estado del 18-19 de julio de 1936 triunfante en Zaragoza, en una inâ”śÂ®dita imagen capturada desde las escaleras de ingreso a la Diputaciâ”śâ”‚n Provincial de la plaza de la Constituciâ”śâ”‚n. Junto a ellas, guardias de asalto y personal afecto. En la plaza, la unidad tranviaria 74 aguarda en la terminal de la lâ”śÂˇnea de Delicias. Al fondo, el reciâ”śÂ®n inaugurado Banco de Espaâ”śâ–’a.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65225600, -0.88145900, '0101000020E6100000C4793881E934ECBF554FE61F7DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51155841951.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51155841951.webp', 'https://www.flickr.com/photos/zaragozaantigua/51155841951/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22427, 'Parque Primo de Rivera c.1968', 'Fuentes del paseo de San Sebastiâ”śĂ­n del parque Primo de Rivera. Fuente: Foto para postal de Comercial Josan. Cesiâ”śâ”‚n de la familia de Josâ”śÂ® Marâ”śÂˇa Sanz Gonzâ”śĂ­lez a Rafael Castillejo. Dataciâ”śâ”‚n y procesado:', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.63543000, -0.89545700, '0101000020E61000003C2D3F7095A7ECBFDA722EC555D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27418277115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27418277115.webp', 'https://www.flickr.com/photos/zaragozaantigua/27418277115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22516, 'Canal Imperial c.1965', 'Familiar imagen capturada en la penunbra del paseo de Colâ”śâ”‚n a la altura del acceso al parque de Primo de Rivera que hacia la izquierda lleva al cabezo de Buenavista, y junto al Canal Imperial de Aragâ”śâ”‚n poco antes de la pronunciada curva que hacia la derecha lleva al recto tramo que conduce al puente de Amâ”śÂ®rica. Al fondo y entre los plâ”śĂ­tanos de sombra, fachada de la veterana fâ”śĂ­brica de harinas "La Imperial de Aragâ”śâ”‚n".', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63328600, -0.89171700, '0101000020E610000001310917F288ECBFE08101840FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51671813411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51671813411.webp', 'https://www.flickr.com/photos/zaragozaantigua/51671813411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25505, 'Calle de la Independencia 1903', 'Fotâ”śâ”‚grafo Yanguas, Arco de la Real Maestranza. 1903. Alfonso XIII fue declarado mayor de edad a los 16 aâ”śâ–’os de edad para poder acceder al trono en 1902. Al aâ”śâ–’o siguiente, entre el 16 y el 19 de octubre, y durante las fiestas del Pilar de 1903, visitâ”śâ”‚ una ciudad engalanada para la ocasiâ”śâ”‚n. Entre otros ornatos, se levantaron tres arcos de triunfo en el espacio pâ”śâ•‘blico mâ”śĂ­s importante de la ciudad: el paseo de Santa Engracia-calle de la Independencia. Quinta Regiâ”śâ”‚n militar, Ayuntamiento y Real Maestranza encargaron la erecciâ”śâ”‚n temporal de estos arcos. La aristocracia local organizada en torno a la Real Maestranza encargâ”śâ”‚ su arco al ingeniero Manuel de Isasi Isasmendi, en la entrada al paseo desde la plaza de la Constituciâ”śâ”‚n, frente por frente con el aâ”śâ•‘n sin terminar monumento a los Mâ”śĂ­rtires de la Religiâ”śâ”‚n (catâ”śâ”‚lica) y de la Patria (espaâ”śâ–’ola). Este arco imitaba en madera una obra de cemento armado y bronce, en estilo modernista, y su remate era copia casi literal de las barandillas del Metro de Parâ”śÂˇs, entre artorchas y figuras de maceros y trompeteros locales. El gran arco ultrasemicircular abocinado fue decorado con bicâ”śÂ®falas â”śĂ­guilas imperiales, y leones. Tras los fastos, este arco fue desmontado. En la imagen, el Arco ubicado a la entrada del Paseo de Santa Engracia. Al fondo, fachada de los edificios que hacen esquina con la calle Cinco de Marzo. Fuente visual: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004. Fuente textual: Mâ”¬Â¬ Pilar Poblador Muga, "Arquitecturas efâ”śÂˇmeras en la Zaragoza de comienzos del siglo XX", 1998.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65168700, -0.88123200, '0101000020E61000009A0986730D33ECBF3B1DC87A6AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16174533128.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16174533128.webp', 'https://www.flickr.com/photos/zaragozaantigua/16174533128/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25508, 'Arco conmemorativo 1908', 'Arco conmemorativo levantado en el arranque del paseo de la Independencia con motivo de la visita del rey Alfonso XIII a la Exposiciâ”śâ”‚n Hispano Francesa de ese aâ”śâ–’o. Fuente visual: foto Ignacio Coyne, en Zaragoza 1908-2008, FCC.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65168700, -0.88123200, '0101000020E61000009A0986730D33ECBF3B1DC87A6AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19392772069.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19392772069.webp', 'https://www.flickr.com/photos/zaragozaantigua/19392772069/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25522, 'Calle de la Independencia 1882', 'Dibujo de Juan Comba y diseâ”śâ–’o de Bernardo Rico basado en una fotografâ”śÂˇa perdida de Anselmo Marâ”śÂˇa Coyne, que ilustra el efâ”śÂˇmero arco de triunfo erigido en la calle de la Independencia durante los festejos por el comienzo de las obras del "camino de hierro que ha de enlazar â”śĂ­ Espaâ”śâ–’a con Francia por el valle de Canfranc". En esta nocturna escena, el imponente arco aparece iluminado con la luz elâ”śÂ®ctrica de las farolas de la calle. Ademâ”śĂ­s, el agua de la artâ”śÂˇstica fuente de su vano fluâ”śÂˇa tornasolada en diversos colores con el sistema de luz de Drummond. Al fondo, la plaza de la Constituciâ”śâ”‚n, la fachada del Coso, y la embocadura a la calle de los Mâ”śĂ­rtires. A la derecha, fuera de cuadro, el comienzo de la calle de San Miguel, en cuya esquina estaba la Casa de Correos y Telâ”śÂ®grafos.', 1882, 1882, 1882, 'Siglo XIX', 'CENTRO', 41.65134900, -0.88165300, '0101000020E610000000732D5A8036ECBF23A46E675FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34721739086.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34721739086.webp', 'https://www.flickr.com/photos/zaragozaantigua/34721739086/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25910, 'Pl. de Espaâ”śâ–’a 1970', 'Colorista imagen de la plaza de Espaâ”śâ–’a con el telâ”śâ”‚n de fondo del edificio de la Diputaciâ”śâ”‚n Provincial. Estacionada delante, la veterana composiciâ”śâ”‚n motor-remolque 103+103 de la tranviaria lâ”śÂˇnea 5 (Venecia-Delicias) orientada hacia la plaza de las Canteras. El sol pega bien duro. Esta captura fue realizada por la australiana Lindsay Bridge un luminoso dâ”śÂˇa de junio de 1970, en su paso por la ciudad durante su viaje a Europa de ese aâ”śâ–’o. Fuente visual: www.flickr.com/photos/intervene/1995723942/in/album-72157...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65211400, -0.88132900, '0101000020E6100000388600E0D833ECBFC2A1B77878D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27279160111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27279160111.webp', 'https://www.flickr.com/photos/zaragozaantigua/27279160111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25922, 'Plaza de la Constituciâ”śâ”‚n 1905', 'Imagen de la antigua plaza de la Constituciâ”śâ”‚n, capturada como base para una comercial postal por la fototipia Hauser y Menet (Madrid). La fachada oeste se perfila con los edificios de la â”śÂ®poca como fondo escâ”śÂ®nico de un espacio de movilidad compartida por peatones y un tranvâ”śÂˇa, a la izquierda, de la elâ”śÂ®ctrica serie de los "Primitivos" de la lâ”śÂˇnea "Madrid", volviendo por la calle de Câ”śĂ­diz desde las estaciones de ferrocarril de Cariâ”śâ–’ena y Campo Sepulcro, o Madrid. Fuente visual: www.todocoleccion.net/', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.65213300, -0.88147200, '0101000020E6100000ECDE8AC40435ECBF39D2191879D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32752605973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32752605973.webp', 'https://www.flickr.com/photos/zaragozaantigua/32752605973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25985, 'Paseo Independencia c.1958', 'Vista tomada desde lo alto de uno de los primeros nâ”śâ•‘meros pares de la calle Mâ”śĂ­rtires de Zaragoza. En primer plano, la plaza de Espaâ”śâ–’a con el Monumento a los Mâ”śĂ­rtires y al fondo el arbolado paseo de la Independencia hasta la plaza de Paraâ”śÂˇso. Fuente visual: AMZ.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65172200, -0.88129100, '0101000020E6100000D84AE82E8933ECBFB70A62A06BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15476296991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15476296991.webp', 'https://www.flickr.com/photos/zaragozaantigua/15476296991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21547, 'Licorera 1922', 'A comienzos de la dâ”śÂ®cada de los aâ”śâ–’os 20 del s. XX, se instalâ”śâ”‚ en el Camino de San Josâ”śÂ® nâ”¬â•‘ 155 la "Industrial Licorera Espaâ”śâ–’ola", sobre lo que hasta entonces habâ”śÂˇan sido feraces campos de cultivo de la antigua huerta de Miraflores. Fue inaugurada el 8 de julio de 1922 bajo la direcciâ”śâ”‚n de Fernando Lâ”śâ”‚pez Cordoncillo, con entrada localizada casi enfrente de la calle Carbâ”śâ”‚ (luego denominada "Uniâ”śâ”‚n", y "Privilegio de la Uniâ”śâ”‚n"), pero en el lado derecho, su instalaciâ”śâ”‚n determinâ”śâ”‚ el desarrollo urbanâ”śÂˇstico de toda esa zona. Tal es asâ”śÂˇ, que con esta calle de acceso pasâ”śâ”‚ a denominarse de "La Licorera", hasta que tras el desmontaje de la fâ”śĂ­brica y la reurbanizaciâ”śâ”‚n de la zona, la calle pasâ”śâ”‚ a denominarse "Escultor Fâ”śÂ®lix Burriel". Fuente visual: Colecciâ”śâ”‚n particular.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.64233100, -0.87320900, '0101000020E6100000E754320054F1EBBF7E1AF7E637D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20231650405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20231650405.webp', 'https://www.flickr.com/photos/zaragozaantigua/20231650405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22556, 'Tren chu-châ”śâ•‘ 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 25/07/1974. Tren del Parque, tren turâ”śÂˇstico, tren chu-châ”śâ•‘, trenecito, tren infantil... Uno de los pocos trenes supervivientes de la ciudad. Tras mâ”śĂ­s de cuarenta aâ”śâ–’os de servicio, sigue activo en el Parque Grande. Aunque no va sobre raâ”śÂˇles.', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63543000, -0.89545700, '0101000020E61000003C2D3F7095A7ECBFDA722EC555D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15127383147.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15127383147.webp', 'https://www.flickr.com/photos/zaragozaantigua/15127383147/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21859, 'C.â”¬â•‘ de San Josâ”śÂ® 1933', 'Imagen capturada en el interior de las instalaciones de la Industrial Licorera Espaâ”śâ–’ola de Salvador Bello, sita en el camino de San Josâ”śÂ® en el lado de los impares, entre la calle de la Licorera y el callejâ”śâ”‚n de la acequia de la Mengrana. En ella se producâ”śÂˇa hielo (hasta 15 toneladas diarias), gaseosas, sifones, espumosos, "Orange Crush", "Sinalco", y un notable repertorio de licores de reconocido prestigio y consumo. La imagen se ha realizado junto al acceso a la factorâ”śÂˇa desde el camino de San Josâ”śÂ®. A la derecha, edificios recayentes a la calle de la Licorera, Al fondo, a la izquierda, la moderna fâ”śĂ­brica de hielo. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64233100, -0.87320900, '0101000020E6100000E754320054F1EBBF7E1AF7E637D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36237782152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36237782152.webp', 'https://www.flickr.com/photos/zaragozaantigua/36237782152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24465, '&quot;La Licorera&quot; 1984', 'Imagen capturada desde Cesâ”śĂ­reo Alierta de lo que hoy se denomina "Patio de la Licorera", en recuerdo mâ”śÂˇnimo de las instalaciones industriales de tratamiento de lâ”śÂˇquidos espirituosos que aquâ”śÂˇ hubo, en lo que ahora apenas era un solar al que daban las traseras de los antiguos edificios de la izquierda (hoy derribados) de la calle Escultor Burriel (antigua calle Licorera), y las traseras frontales de los trillizos bloques de viviendas de la Avenida S. Josâ”śÂ® (nâ”¬â•‘ 62, 64 y 66), de 1964. En 1988 la zona fue finalmente urbanizada completamente, con el derribo de las parcelas, restos de naves y edificaciones de la imagen, y la construcciâ”śâ”‚n sobre ellas de los actuales bloques nâ”¬â•‘ 54, 56, 58 de la Avenida de S. Josâ”śÂ®, y los bloques nâ”¬â•‘ 1, 3, 5, 7 y 9 de la calle Escultor Burriel. Al cerramiento de la manzana y la configuraciâ”śâ”‚n del actual "Patio de la Licorera" contribuyeron tambiâ”śÂ®n los nuevos bloques de Cesâ”śĂ­reo Alierta nâ”¬â•‘ 39-41, 43, 45, 47, 49 y 53. Fuente visual: AVV San Josâ”śÂ®', 1984, 1984, 1984, 'Anos 80', 'CENTRO', 41.64169800, -0.87403500, '0101000020E610000047E6913F18F8EBBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20063142570.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20063142570.webp', 'https://www.flickr.com/photos/zaragozaantigua/20063142570/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24477, 'La Licorera 1988', 'Antiguo ingreso a La Licorera, Industrial Licorera Espaâ”śâ–’ola de Salvador Bello, durante la temporal convivencia con la entrada/salida de garajes del bloque de viviendas del nâ”¬â•‘ 5 de la calle del Escultor Fâ”śÂ®lix Burriel, en construcciâ”śâ”‚n al fondo de la imagen. Esta espirituosa factorâ”śÂˇa estuvo activa desde principios del siglo, produciendo entre otros productos el reconocible ron que se anuncia en la puerta, ademâ”śĂ­s de gaseosas, sifones, espumosos, y una moderna fâ”śĂ­brica de hielo. Fuente: "Memoria de las calles de Zaragoza", Juliâ”śĂ­n Ruiz Marâ”śÂˇn, Librerâ”śÂˇa General, 2003.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.64169800, -0.87403500, '0101000020E610000047E6913F18F8EBBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21545379408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21545379408.webp', 'https://www.flickr.com/photos/zaragozaantigua/21545379408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25766, 'Calle Licorera 1976', 'Calle de la Licorera, centrada en primer tâ”śÂ®rmino en una fâ”śĂ­brica de colas, esmaltes y pinturas. A la izquierda, la Industrial Licorera Espaâ”śâ–’ola que dio su nombre a este vial, productora de anisados, licores, jarabes espumosos y hielo cristalino desde principios de siglo. Desde 1979 esta es la calle del Escultor Fâ”śÂ®lix Burriel. Al fondo, parcelas de los nâ”śâ•‘meros 53-55 de la avenida de San Josâ”śÂ®, esquineros con la calle del Privilegio de la Uniâ”śâ”‚n.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64229300, -0.87428000, '0101000020E61000000A80F10C1AFAEBBF91B932A836D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32961830920.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32961830920.webp', 'https://www.flickr.com/photos/zaragozaantigua/32961830920/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20970, 'Plano de Santa Fe y alrededores 1853', '"Plano en el que se demarca los Trece solares vencidos por la Excma. Diputaciâ”śâ”‚n Provincial y la continuaciâ”śâ”‚n de la calle de San Miguel hasta la Iglesia de San Ildefonso". Juan Gimeno, arquitecto, 1853. Fuente: Archivo Municipal de Zaragoza.', 1853, 1853, 1853, 'Siglo XIX', 'CENTRO', 41.65243200, -0.88380900, '0101000020E61000008522DDCF2948ECBF936E4BE482D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19134215638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19134215638.webp', 'https://www.flickr.com/photos/zaragozaantigua/19134215638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21068, 'Convento de Santa Fe 1878', 'Imagen del claustro alto del desaparecido Convento de Santa Fe, en la plaza del mismo nombre (luego de Salamero), en la â”śÂ®poca en que era sede del Museo Provincial de Zaragoza y Academia de Bellas Artes (1848-1896). En origen fue convento de MM. Religiosas de Santa Fe de la Penitencia, o Arrepentidas, de la Orden de Santo Domingo, fundado a mediados del XVI en la calle Azoque de la "Morerâ”śÂˇa", con el propâ”śâ”‚sito de â”¬Â˝reorientarâ”¬â•— la vida de las mujeres que habâ”śÂˇan errado hacia el "buen camino", reencauzando su vida al "servicio divino". Desempeâ”śâ–’arâ”śÂˇa esta oximorâ”śâ”‚nica funciâ”śâ”‚n hasta 1834. En la imagen, aspecto parcial del claustro alto del antiguo convento, con una hilera un tanto descompuesta, para ser un Museo, de modillones en madera desmontados de alguno de esos aleros volados de las palaciegas y nobiliarias casas desaparecidas. En 1908, aâ”śâ–’o de notables prodigios urbanâ”śÂˇsticos en la ciudad, la piqueta se llevâ”śâ”‚ por delante este edificio, para ensanchar la calle. Tal cual. Este notable claustro renacentista tardâ”śÂˇo, como no habâ”śÂˇa otro en la ciudad, al menos quedâ”śâ”‚ inmortalizado en algunas fotos hechas por franceses. Fuente Visual: www.mcu.es/ Fototeca del Patrimonio (Archivo Ruiz Vernacci), Jean Laurent y Câ”śÂˇa. 1872-1879. "Patio del Museo Provincial".', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.65251300, -0.88444200, '0101000020E6100000C0AE264F594DECBF809BC58B85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17444001766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17444001766.webp', 'https://www.flickr.com/photos/zaragozaantigua/17444001766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21416, 'Calle de Alfonso I 1915', 'Paso de la carroza del Ayuntamiento por el primer tramo de la calle de Alfonso I, durante la cabalgata anunciadora de las fiestas del Pilar, el domingo 10 de octubre de 1915. A la izquierda, marquesina del Cafâ”śÂ® Moderno esquinero con el Coso Alto. En el centro de la imagen, el antiguo inmueble del nâ”¬â•‘ 3 de la calle, luego derribado y sobre cuyo solar se construirâ”śÂˇa poco despuâ”śÂ®s, con la lâ”śÂˇnea de fachada ya homologada respecto a su vecino de la derecha, el referencial edificio de los almacenes El â”śĂĽguila. En primer tâ”śÂ®rmino, uno de los jâ”śâ”‚venes exploradores abanderados que formaban parte de la cabalgata.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65333500, -0.88197600, '0101000020E6100000B16B7BBB2539ECBF842A357BA0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30450950142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30450950142.webp', 'https://www.flickr.com/photos/zaragozaantigua/30450950142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
